class Solution:
    def isArraySpecial(self, nums):
        for i in range(len(nums) - 1):
            if nums[i] % 2 == nums[i+1] % 2:
                return False
        return True

solutions.python:
class Solution:
    def isArraySpecial(self, nums):
        return all(nums[i] % 2 != nums[i+1] % 2 for i in range(len(nums) - 1))

